import requests
import json

base_url = "<your_kong_url>/kong"
admin_token = "<your_admin_token>"
headers = {'Content-Type': 'application/json', 'Accept': 'application/json', 'Authorization': f'Bearer {admin_token}'}

service_data = {
    "id": "my-service",
    "name": "My Service",
    "url": "http://example.com"
}

response = requests.post(f"{base_url}/services", json=service_data, headers=headers)
print("Service created:", response.json())

route_data = {
    "id": "my-route",
    "service": service_data["id"],
    "hosts": ["example.com"],
    "paths": ["/"]
}

response = requests.post(f"{base_url}/services/{service_data['id']}/routes", json=route_data, headers=headers)
print("Route created:", response.json())

target_data = {
    "id": "my-target",
    "host": "example.com",
    "port": 80
}

response = requests.post(f"{base_url}/services/{service_data['id']}/routes/{route_data['ids'][0]}/ targets", json=target_data, headers=headers)
print("Target created:", response.json())